I now have comprehensive understanding of the codebase. Let me produce the detailed implementation plan.

---

## Implementation Plan: Stepper Compound Component

### Overview

The Stepper is a fully custom compound component (no Radix/Base-UI primitive exists for steppers), so it follows the Carousel pattern: custom React context, no external primitive dependency, same code in radix and base layers with only import path differences.

---

## Phase 1: Understand Alphabetical Placement

"stepper" sorts between "spinner" and "switch" in all registries.

In `bases/radix/ui/_registry.ts`: insert after the `spinner` entry (line ~832) and before the `switch` entry (line ~835).

In `bases/base/ui/_registry.ts`: insert after the `spinner` entry (~line 833) and before the `switch` entry (~line 843).

In `new-york-v4/ui/_registry.ts`: insert after the `spinner` entry (~line 563) and before the `switch` entry (~line 564).

In `bases/radix/examples/_registry.ts`: insert after `spinner-example` (~line 766) and before `switch-example` (~line 778).

In `new-york-v4/examples/_registry.ts`: insert after `spinner-item` (~line 2124) and before `switch-demo` (~line 2126).

---

## Phase 2: Create `registry/bases/radix/ui/stepper.tsx`

**Path:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775474101635-1tujer/apps/v4/registry/bases/radix/ui/stepper.tsx`

```tsx
"use client"

import * as React from "react"

import { cn } from "@/registry/bases/radix/lib/utils"
import { IconPlaceholder } from "@/app/(create)/components/icon-placeholder"

type StepperContextProps = {
  value: string
  onValueChange: (value: string) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

type StepperItemContextProps = {
  value: string
  state: "active" | "completed" | "pending"
  disabled: boolean
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

type StepperProps = {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  value: valueProp,
  defaultValue,
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  const [value, setValue] = React.useState(defaultValue ?? "")

  const isControlled = valueProp !== undefined
  const currentValue = isControlled ? valueProp : value

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (!isControlled) {
        setValue(newValue)
      }
      onValueChange?.(newValue)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{
        value: currentValue,
        onValueChange: handleValueChange,
        orientation,
      }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper group/stepper flex",
          orientation === "horizontal" ? "flex-row items-start" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

type StepperItemProps = {
  value: string
  completed?: boolean
  disabled?: boolean
}

function StepperItem({
  value,
  completed = false,
  disabled = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperItemProps) {
  const { value: stepperValue, orientation } = useStepper()

  const state: "active" | "completed" | "pending" =
    value === stepperValue
      ? "active"
      : completed
      ? "completed"
      : "pending"

  return (
    <StepperItemContext.Provider value={{ value, state, disabled }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-disabled={disabled ? "" : undefined}
        data-orientation={orientation}
        className={cn(
          "cn-stepper-item group/stepper-item flex",
          orientation === "horizontal"
            ? "flex-col items-center"
            : "flex-row items-start",
          disabled && "pointer-events-none opacity-50",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { value, disabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      disabled={disabled}
      className={cn(
        "cn-stepper-trigger inline-flex items-center gap-2 focus-visible:outline-none focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      onClick={() => onValueChange(value)}
      {...props}
    >
      {children}
    </button>
  )
}

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"span">) {
  const { state } = useStepperItem()

  return (
    <span
      data-slot="stepper-indicator"
      data-state={state}
      className={cn("cn-stepper-indicator", className)}
      {...props}
    >
      {state === "completed" ? (
        <IconPlaceholder
          lucide="CheckIcon"
          tabler="IconCheck"
          hugeicons="CheckmarkCircle02Icon"
          phosphor="CheckIcon"
          remixicon="RiCheckLine"
          className="cn-stepper-indicator-check"
        />
      ) : (
        children
      )}
    </span>
  )
}

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("cn-stepper-title", className)}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("cn-stepper-description", className)}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      className={cn(
        "cn-stepper-separator bg-border",
        orientation === "horizontal"
          ? "mt-4 h-px flex-1"
          : "ml-4 w-px self-stretch",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { value: stepperValue } = useStepper()
  const { value } = useStepperItem()

  if (value !== stepperValue) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("cn-stepper-content", className)}
      {...props}
    />
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
  useStepperItem,
}
```

**Key design decisions:**
- Uses `"use client"` directive (client-side state, event handlers).
- Controlled/uncontrolled pattern via `useState` + `isControlled` guard, matching Radix primitives' convention used elsewhere.
- `StepperContent` renders `null` when its item is not active (not hidden via CSS, so it cleanly unmounts — consistent with how `TabsContent` is conditionally shown).
- `data-slot` attributes on every element for consistency with the whole library.
- `cn-stepper*` prefixed class names for themed styling hooks.
- `IconPlaceholder` with all icon-set props for the completed checkmark, matching Carousel's pattern.

---

