## Phase 4: Create `registry/new-york-v4/ui/stepper.tsx`

**Path:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775474101635-1tujer/apps/v4/registry/new-york-v4/ui/stepper.tsx`

This layer drops `IconPlaceholder` in favour of `lucide-react` icons directly, uses `cn` from `@/lib/utils`, uses concrete Tailwind classes instead of `cn-*` theme tokens, and imports `React` with `* as React`.

```tsx
"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

type StepperContextProps = {
  value: string
  onValueChange: (value: string) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

type StepperItemContextProps = {
  value: string
  state: "active" | "completed" | "pending"
  disabled: boolean
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

type StepperProps = {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  value: valueProp,
  defaultValue,
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  const [value, setValue] = React.useState(defaultValue ?? "")

  const isControlled = valueProp !== undefined
  const currentValue = isControlled ? valueProp : value

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (!isControlled) {
        setValue(newValue)
      }
      onValueChange?.(newValue)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{
        value: currentValue,
        onValueChange: handleValueChange,
        orientation,
      }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex",
          orientation === "horizontal" ? "flex-row items-start" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

type StepperItemProps = {
  value: string
  completed?: boolean
  disabled?: boolean
}

function StepperItem({
  value,
  completed = false,
  disabled = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperItemProps) {
  const { value: stepperValue, orientation } = useStepper()

  const state: "active" | "completed" | "pending" =
    value === stepperValue
      ? "active"
      : completed
      ? "completed"
      : "pending"

  return (
    <StepperItemContext.Provider value={{ value, state, disabled }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-disabled={disabled ? "" : undefined}
        data-orientation={orientation}
        className={cn(
          "group/stepper-item flex",
          orientation === "horizontal"
            ? "flex-col items-center"
            : "flex-row items-start gap-4",
          disabled && "pointer-events-none opacity-50",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { value, disabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      disabled={disabled}
      className={cn(
        "inline-flex items-center gap-2 rounded-md focus-visible:outline-none focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      onClick={() => onValueChange(value)}
      {...props}
    >
      {children}
    </button>
  )
}

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"span">) {
  const { state } = useStepperItem()

  return (
    <span
      data-slot="stepper-indicator"
      data-state={state}
      className={cn(
        "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors",
        state === "active" &&
          "border-primary bg-primary text-primary-foreground",
        state === "completed" &&
          "border-primary bg-primary text-primary-foreground",
        state === "pending" &&
          "border-muted-foreground/30 bg-background text-muted-foreground",
        className
      )}
      {...props}
    >
      {state === "completed" ? (
        <CheckIcon className="size-4" />
      ) : (
        children
      )}
    </span>
  )
}

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium leading-none", className)}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      className={cn(
        "bg-border transition-colors group-data-[orientation=horizontal]/stepper:mt-4 group-data-[orientation=horizontal]/stepper:h-px group-data-[orientation=horizontal]/stepper:flex-1 group-data-[orientation=vertical]/stepper:ml-4 group-data-[orientation=vertical]/stepper:w-px group-data-[orientation=vertical]/stepper:self-stretch",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { value: stepperValue } = useStepper()
  const { value } = useStepperItem()

  if (value !== stepperValue) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("ml-12 pb-4 text-sm", className)}
      {...props}
    />
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
  useStepperItem,
}
```

**Key new-york-v4 differences from bases:**
- `import { CheckIcon } from "lucide-react"` instead of `IconPlaceholder`.
- `import { cn } from "@/lib/utils"` (no registry sub-path).
- Concrete Tailwind classes on all elements: `size-8`, `rounded-full`, `border-2`, `text-sm`, `text-muted-foreground`, etc.
- No `cn-*` prefixed class tokens.
- `group-data-[orientation=...]/stepper:` selectors for `StepperSeparator` (following the new-york-v4 tabs pattern where `data-[orientation=...]` is used rather than shorthand `data-horizontal`/`data-vertical`).
- `StepperContent` adds an `ml-12 pb-4` default positioning offset for vertical layout.

