            <StepperIndicator>3</StepperIndicator>
          </StepperTrigger>
        </StepperItem>
      </Stepper>
    </Example>
  )
}

function StepperControlled() {
  const [step, setStep] = React.useState("step-1")
  const steps = ["step-1", "step-2", "step-3"]
  const currentIndex = steps.indexOf(step)

  return (
    <Example title="Controlled">
      <div className="flex flex-col gap-4">
        <Stepper value={step} onValueChange={setStep} className="w-full max-w-md">
          {steps.map((s, i) => (
            <React.Fragment key={s}>
              <StepperItem
                value={s}
                completed={steps.indexOf(s) < currentIndex}
              >
                <StepperTrigger>
                  <StepperIndicator>{i + 1}</StepperIndicator>
                </StepperTrigger>
              </StepperItem>
              {i < steps.length - 1 && <StepperSeparator />}
            </React.Fragment>
          ))}
        </Stepper>
        <div className="flex gap-2">
          <Button
            variant="outline"
            size="sm"
            disabled={currentIndex === 0}
            onClick={() => setStep(steps[currentIndex - 1])}
          >
            Back
          </Button>
          <Button
            size="sm"
            disabled={currentIndex === steps.length - 1}
            onClick={() => setStep(steps[currentIndex + 1])}
          >
            Next
          </Button>
        </div>
      </div>
    </Example>
  )
}
```

**Note on `StepperSeparator` placement**: In the horizontal layout, separators go between `StepperItem` elements as siblings of the item (not children), because they need to stretch between items in the flex row. In the vertical layout, they go inside `StepperItem` as children so they stretch downward from the item's indicator. The controlled example shows the horizontal sibling pattern explicitly.

