# Plan: Stepper Compound Component

## Context

Add a new "Stepper" compound component to the shadcn/ui v4 component library for multi-step wizard and onboarding flows. No Radix or @base-ui/react primitive exists for steppers, so this follows the **Carousel pattern**: custom React context, no external primitive dependency.

The library has three layers:
- `registry/bases/radix/ui/` — abstract, `cn-*` theme tokens, `IconPlaceholder`, imports from `@/registry/bases/radix/lib/utils`
- `registry/bases/base/ui/` — identical structure but different import path (`@/registry/bases/base/lib/utils`)
- `registry/new-york-v4/ui/` — concrete Tailwind classes, `lucide-react`, imports from `@/lib/utils`

---

## Sub-components & API Design

```tsx
<Stepper value="step-2" onValueChange={setStep} orientation="horizontal">
  <StepperItem value="step-1" completed>
    <StepperTrigger>
      <StepperIndicator>1</StepperIndicator>
      <StepperTitle>Account</StepperTitle>
    </StepperTrigger>
  </StepperItem>
  <StepperSeparator />          {/* sibling between items, like BreadcrumbSeparator */}
  <StepperItem value="step-2">
    <StepperTrigger>
      <StepperIndicator>2</StepperIndicator>
      <div>
        <StepperTitle>Profile</StepperTitle>
        <StepperDescription>Set up your profile</StepperDescription>
      </div>
    </StepperTrigger>
    <StepperContent>            {/* child of StepperItem; hidden when step is inactive */}
      Panel content here
    </StepperContent>
  </StepperItem>
  <StepperSeparator />
  <StepperItem value="step-3">
    <StepperTrigger>
      <StepperIndicator>3</StepperIndicator>
      <StepperTitle>Review</StepperTitle>
    </StepperTrigger>
  </StepperItem>
</Stepper>
```

### Key design decisions
- **`StepperSeparator`** is a sibling between `StepperItem` elements (like `BreadcrumbSeparator`), not a child.
- **`StepperContent`** is a child of `StepperItem`; uses `useStepperItem()` context to show/hide.
- **State** on `StepperItem`: `data-state="active"` when `item.value === stepper.value`; `"completed"` when `completed` prop is set; otherwise `"pending"`. User manages completion externally.
- **Controlled + uncontrolled** via `value` / `defaultValue` / `onValueChange` (same pattern as Tabs).
- `"use client"` directive required (state, event handlers).
- Every element has a `data-slot="stepper[-*]"` attribute.

### Two contexts
1. `StepperContext` — `{ value, onValueChange, orientation }`
2. `StepperItemContext` — `{ value, state: "active"|"completed"|"pending", disabled }`

---

## Files to Create (5 new files)

### 1. `apps/v4/registry/bases/radix/ui/stepper.tsx`

```tsx
"use client"

import * as React from "react"

import { cn } from "@/registry/bases/radix/lib/utils"
import { IconPlaceholder } from "@/app/(create)/components/icon-placeholder"

type StepperContextProps = {
  value: string
  onValueChange: (value: string) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

type StepperItemContextProps = {
  value: string
  state: "active" | "completed" | "pending"
  disabled: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

type StepperProps = {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  value: valueProp,
  defaultValue,
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  const [uncontrolledValue, setUncontrolledValue] = React.useState(
    defaultValue ?? ""
  )
  const isControlled = valueProp !== undefined
  const currentValue = isControlled ? valueProp : uncontrolledValue

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (!isControlled) setUncontrolledValue(newValue)
      onValueChange?.(newValue)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value: currentValue, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper group/stepper flex",
          orientation === "horizontal" ? "flex-row items-start" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

type StepperItemProps = {
  value: string
  completed?: boolean
  disabled?: boolean
}

function StepperItem({
  value,
  completed = false,
  disabled = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperItemProps) {
  const { value: stepperValue } = useStepper()
  const state: "active" | "completed" | "pending" =
    value === stepperValue ? "active" : completed ? "completed" : "pending"

  return (
    <StepperItemContext.Provider value={{ value, state, disabled }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-disabled={disabled ? "" : undefined}
        className={cn(
          "cn-stepper-item group/stepper-item flex flex-col",
          disabled && "pointer-events-none opacity-50",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { value, disabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      disabled={disabled}
      className={cn(
        "cn-stepper-trigger inline-flex items-center gap-2 focus-visible:outline-none focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      onClick={() => onValueChange(value)}
      {...props}
    >
      {children}
    </button>
  )
}

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"span">) {
  const { state } = useStepperItem()

  return (
    <span
      data-slot="stepper-indicator"
      data-state={state}
      className={cn("cn-stepper-indicator", className)}
      {...props}
    >
      {state === "completed" ? (
        <IconPlaceholder
          lucide="CheckIcon"
          tabler="IconCheck"
          hugeicons="CheckmarkCircle02Icon"
          phosphor="CheckIcon"
          remixicon="RiCheckLine"
          className="cn-stepper-indicator-check"
        />
      ) : (
        children
      )}
    </span>
  )
}

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("cn-stepper-title", className)}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("cn-stepper-description", className)}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      className={cn(
        "cn-stepper-separator shrink-0 bg-border",
        orientation === "horizontal" ? "mt-4 h-px flex-1" : "ml-4 h-6 w-px",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { value: stepperValue } = useStepper()
  const { value } = useStepperItem()

  if (value !== stepperValue) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("cn-stepper-content", className)}
      {...props}
    />
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
  useStepperItem,
}
```

