"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

type StepperOrientation = "horizontal" | "vertical"
type StepperState = "active" | "completed" | "pending"

interface StepperContextValue {
  value: number
  onValueChange: (value: number) => void
  orientation: StepperOrientation
  totalSteps: number
  setTotalSteps: React.Dispatch<React.SetStateAction<number>>
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

interface StepperItemContextValue {
  step: number
  state: StepperState
  disabled: boolean
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ---------------------------------------------------------------------------
// Stepper (root)
// ---------------------------------------------------------------------------

interface StepperProps extends React.ComponentProps<"div"> {
  value?: number
  defaultValue?: number
  onValueChange?: (value: number) => void
  orientation?: StepperOrientation
}

function Stepper({
  value: valueProp,
  defaultValue = 1,
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: StepperProps) {
  const [internalValue, setInternalValue] = React.useState(defaultValue)
  const [totalSteps, setTotalSteps] = React.useState(0)

  const isControlled = valueProp !== undefined
  const value = isControlled ? valueProp : internalValue

  const handleValueChange = React.useCallback(
    (next: number) => {
      if (!isControlled) setInternalValue(next)
      onValueChange?.(next)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation, totalSteps, setTotalSteps }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-row items-start"
            : "flex-col items-stretch",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperItem
// ---------------------------------------------------------------------------

interface StepperItemProps extends React.ComponentProps<"div"> {
  step: number
  completed?: boolean
  disabled?: boolean
}

function StepperItem({
  step,
  completed: completedProp = false,
  disabled = false,
  className,
  children,
  ...props
}: StepperItemProps) {
  const { value, orientation, setTotalSteps } = useStepper()

  React.useEffect(() => {
    setTotalSteps((prev) => Math.max(prev, step))
  }, [step, setTotalSteps])

  const state: StepperState =
    completedProp || step < value
      ? "completed"
      : step === value
        ? "active"
        : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state, disabled }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-orientation={orientation}
        data-disabled={disabled ? "" : undefined}
        className={cn(
          "group/stepper-item flex",
          orientation === "horizontal"
            ? "flex-col items-center"
            : "flex-row items-start",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperTrigger
// ---------------------------------------------------------------------------

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { step, state, disabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={state}
      disabled={disabled}
      onClick={() => onValueChange(step)}
      className={cn(
        "inline-flex cursor-pointer items-center gap-2 rounded-sm outline-none",
        "focus-visible:ring-ring/50 focus-visible:ring-[3px]",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ---------------------------------------------------------------------------
// StepperIndicator
// ---------------------------------------------------------------------------

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"span">) {
  const { state, step } = useStepperItem()

  return (
    <span
      data-slot="stepper-indicator"
      data-state={state}
      className={cn(
        "flex size-8 shrink-0 items-center justify-center rounded-full text-sm font-medium transition-colors",
        state === "completed" &&
          "bg-primary text-primary-foreground",
        state === "active" &&
          "border-2 border-primary bg-background text-primary",
        state === "pending" &&
          "border-2 border-muted-foreground/30 bg-background text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? (
        state === "completed" ? (
          <CheckIcon className="size-4" />
        ) : (
          <span>{step}</span>
        )
      )}
    </span>
  )
}

// ---------------------------------------------------------------------------
// StepperTitle
// ---------------------------------------------------------------------------

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-medium leading-tight",
        state === "pending" && "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription
// ---------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-description"
      data-state={state}
      className={cn(
        "text-xs text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperSeparator
// ---------------------------------------------------------------------------

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      aria-hidden
      className={cn(
        "bg-border transition-colors",
        orientation === "horizontal"
          ? "mt-4 h-px flex-1"
          : "ml-4 w-px self-stretch",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperContent
// ---------------------------------------------------------------------------

interface StepperContentProps extends React.ComponentProps<"div"> {
  /** Render content even when not active (hidden with CSS). Defaults to false (unmount). */
  forceMount?: boolean
}

function StepperContent({
  forceMount = false,
  className,
  children,
  ...props
}: StepperContentProps) {
  const { state } = useStepperItem()
  const { orientation } = useStepper()

  if (!forceMount && state !== "active") return null

  return (
    <div
      data-slot="stepper-content"
      data-state={state}
      data-orientation={orientation}
      hidden={forceMount && state !== "active"}
      className={cn(
        "mt-2",
        orientation === "vertical" && "ml-10",
        className
      )}
      {...props}
    >
      {children}
    </div>
  )
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
  useStepperItem,
}

