"use client"

import * as React from "react"

import {
  Example,
  ExampleWrapper,
} from "@/registry/bases/radix/components/example"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperIndicator,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/bases/radix/ui/stepper"

export default function StepperExample() {
  return (
    <ExampleWrapper className="lg:grid-cols-1">
      <StepperHorizontal />
      <StepperVertical />
      <StepperWithContent />
      <StepperWithDescriptions />
      <StepperControlled />
    </ExampleWrapper>
  )
}

// ---------------------------------------------------------------------------
// Horizontal (default)
// ---------------------------------------------------------------------------

const STEPS_BASIC = [
  { step: 1, title: "Account" },
  { step: 2, title: "Profile" },
  { step: 3, title: "Review" },
]

function StepperHorizontal() {
  const [value, setValue] = React.useState(2)

  return (
    <Example title="Horizontal">
      <Stepper value={value} onValueChange={setValue} className="w-full">
        {STEPS_BASIC.map(({ step, title }, index) => (
          <React.Fragment key={step}>
            <StepperItem step={step}>
              <StepperTrigger>
                <StepperIndicator />
                <StepperTitle>{title}</StepperTitle>
              </StepperTrigger>
            </StepperItem>
            {index < STEPS_BASIC.length - 1 && <StepperSeparator />}
          </React.Fragment>
        ))}
      </Stepper>
    </Example>
  )
}

// ---------------------------------------------------------------------------
// Vertical
// ---------------------------------------------------------------------------

function StepperVertical() {
  const [value, setValue] = React.useState(2)

  return (
    <Example title="Vertical">
      <Stepper
        value={value}
        onValueChange={setValue}
        orientation="vertical"
        className="w-full max-w-xs"
      >
        {STEPS_BASIC.map(({ step, title }, index) => (
          <React.Fragment key={step}>
            <StepperItem step={step}>
              <StepperTrigger>
                <StepperIndicator />
                <StepperTitle>{title}</StepperTitle>
              </StepperTrigger>
            </StepperItem>
            {index < STEPS_BASIC.length - 1 && <StepperSeparator />}
          </React.Fragment>
        ))}
      </Stepper>
    </Example>
  )
}

// ---------------------------------------------------------------------------
// With inline content (vertical)
// ---------------------------------------------------------------------------

const STEPS_CONTENT = [
  {
    step: 1,
    title: "Create account",
    content: "Enter your email address and choose a secure password.",
  },
  {
    step: 2,
    title: "Verify email",
    content: "Check your inbox and click the verification link we sent you.",
  },
  {
    step: 3,
    title: "Complete profile",
    content: "Add your name, avatar, and any other details you'd like to share.",
  },
]

function StepperWithContent() {
  const [value, setValue] = React.useState(2)

  return (
    <Example title="With Content">
      <Stepper
        value={value}
        onValueChange={setValue}
        orientation="vertical"
        className="w-full max-w-sm"
      >
        {STEPS_CONTENT.map(({ step, title, content }, index) => (
          <React.Fragment key={step}>
            <StepperItem step={step}>
              <StepperTrigger>
                <StepperIndicator />
                <StepperTitle>{title}</StepperTitle>
              </StepperTrigger>
              <StepperContent>
                <p className="text-sm text-muted-foreground">{content}</p>
              </StepperContent>
            </StepperItem>
            {index < STEPS_CONTENT.length - 1 && <StepperSeparator />}
          </React.Fragment>
        ))}
      </Stepper>
    </Example>
  )
}

// ---------------------------------------------------------------------------
// With descriptions (horizontal)
// ---------------------------------------------------------------------------

const STEPS_DESC = [
  { step: 1, title: "Cart", description: "Review items" },
  { step: 2, title: "Shipping", description: "Choose delivery" },
  { step: 3, title: "Payment", description: "Enter details" },
  { step: 4, title: "Confirm", description: "Place order" },
]

function StepperWithDescriptions() {
  const [value, setValue] = React.useState(3)

  return (
    <Example title="With Descriptions">
      <Stepper value={value} onValueChange={setValue} className="w-full">
        {STEPS_DESC.map(({ step, title, description }, index) => (
          <React.Fragment key={step}>
            <StepperItem step={step}>
              <StepperTrigger>
                <StepperIndicator />
                <div className="flex flex-col items-start">
                  <StepperTitle>{title}</StepperTitle>
                  <StepperDescription>{description}</StepperDescription>
                </div>
              </StepperTrigger>
            </StepperItem>
            {index < STEPS_DESC.length - 1 && <StepperSeparator />}
          </React.Fragment>
        ))}
      </Stepper>
    </Example>
  )
}

// ---------------------------------------------------------------------------
// Controlled wizard
// ---------------------------------------------------------------------------

const STEPS_WIZARD = [
  { step: 1, title: "Details" },
  { step: 2, title: "Settings" },
  { step: 3, title: "Done" },
]

function StepperControlled() {
  const [value, setValue] = React.useState(1)
  const total = STEPS_WIZARD.length

  return (
    <Example title="Controlled Wizard">
      <div className="flex w-full flex-col gap-6">
        <Stepper value={value} onValueChange={setValue} className="w-full">
          {STEPS_WIZARD.map(({ step, title }, index) => (
            <React.Fragment key={step}>
              <StepperItem step={step}>
                <StepperTrigger>
                  <StepperIndicator />
                  <StepperTitle>{title}</StepperTitle>
                </StepperTrigger>
              </StepperItem>
              {index < STEPS_WIZARD.length - 1 && <StepperSeparator />}
            </React.Fragment>
          ))}
        </Stepper>

        <div className="rounded-lg border p-4 text-sm text-muted-foreground">
          Step {value} of {total}:{" "}
          {STEPS_WIZARD.find((s) => s.step === value)?.title}
        </div>

        <div className="flex gap-2">
          <button
            type="button"
            disabled={value <= 1}
            onClick={() => setValue((v) => Math.max(1, v - 1))}
            className="rounded-md border px-3 py-1.5 text-sm disabled:opacity-50"
          >
            Back
          </button>
          <button
            type="button"
            disabled={value >= total}
            onClick={() => setValue((v) => Math.min(total, v + 1))}
            className="rounded-md bg-primary px-3 py-1.5 text-sm text-primary-foreground disabled:opacity-50"
          >
            {value === total ? "Finish" : "Next"}
          </button>
        </div>
      </div>
    </Example>
  )
}

